# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balance(transactions, initial_balance):
    current_balance = initial_balance
    transaction_types = {
        'deposit': lambda amount: current_balance + amount,
        'withdrawal': lambda amount: current_balance - amount,
        'transfer_in': lambda amount: current_balance + amount,
        'transfer_out': lambda amount: current_balance - amount
    }

    for transaction in transactions:
        if transaction['type'] in transaction_types:
            current_balance = transaction_types[transaction['type']](transaction['amount'])
        else:
            raise ValueError(f"Invalid transaction type: {transaction['type']}")

    return current_balance